import UIKit

// MARK: - Network Configuration

enum APIEnvironment {
    case production
    case legacy
    
    var baseURL: String {
        switch self {
        case .production:
            return "https://api.example.com"
        case .legacy:
            return "http://legacy.internal"
        }
    }
}

// MARK: - Network Error

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case noData
    case decodingError(Error)
    case serverError(Int)
    case networkError(Error)
    case sslError
    case unauthorized
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .serverError(let code):
            return "Server error with status code: \(code)"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .sslError:
            return "SSL/TLS connection error"
        case .unauthorized:
            return "Unauthorized access"
        }
    }
}

// MARK: - API Response Models

struct APIResponse<T: Codable>: Codable {
    let success: Bool
    let data: T?
    let message: String?
}

struct User: Codable {
    let id: Int
    let name: String
    let email: String
}

struct LegacyRecord: Codable {
    let recordId: String
    let value: String
    let timestamp: String
}

// MARK: - Network Session Delegate for SSL Handling

class NetworkSessionDelegate: NSObject, URLSessionDelegate {
    
    // Trusted internal domains that may use self-signed certificates
    private let trustedInternalDomains = ["legacy.internal"]
    
    func urlSession(_ session: URLSession,
                    didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              let host = challenge.protectionSpace.host as String? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // For production API - perform standard SSL validation
        if host == "api.example.com" {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
            return
        }
        
        // For legacy internal systems - allow self-signed certificates
        if trustedInternalDomains.contains(where: { host.hasSuffix($0) }) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
            return
        }
        
        // For all other domains, use default handling
        completionHandler(.performDefaultHandling, nil)
    }
}

// MARK: - Network Manager

class NetworkManager {
    
    static let shared = NetworkManager()
    
    private let sessionDelegate = NetworkSessionDelegate()
    private lazy var secureSession: URLSession = {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        return URLSession(configuration: config, delegate: sessionDelegate, delegateQueue: nil)
    }()
    
    private lazy var legacySession: URLSession = {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 45
        config.timeoutIntervalForResource = 90
        return URLSession(configuration: config, delegate: sessionDelegate, delegateQueue: nil)
    }()
    
    private var authToken: String?
    
    private init() {}
    
    // MARK: - Authentication
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    // MARK: - Generic Request Method
    
    func request<T: Codable>(
        environment: APIEnvironment,
        path: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil
    ) async throws -> T {
        
        let urlString = "\(environment.baseURL)\(path)"
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Add auth token for production API
        if environment == .production, let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        // Add custom headers
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        if let body = body {
            request.httpBody = body
        }
        
        let session = (environment == .legacy) ? legacySession : secureSession
        
        let (data, response): (Data, URLResponse)
        
        do {
            (data, response) = try await session.data(for: request)
        } catch let error as NSError {
            if error.domain == NSURLErrorDomain &&
                (error.code == NSURLErrorSecureConnectionFailed ||
                 error.code == NSURLErrorServerCertificateUntrusted) {
                throw NetworkError.sslError
            }
            throw NetworkError.networkError(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.noData
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            break
        case 401:
            throw NetworkError.unauthorized
        default:
            throw NetworkError.serverError(httpResponse.statusCode)
        }
        
        do {
            let decoded = try JSONDecoder().decode(T.self, from: data)
            return decoded
        } catch {
            throw NetworkError.decodingError(error)
        }
    }
    
    // MARK: - Production API Methods
    
    func fetchUsers() async throws -> [User] {
        let response: APIResponse<[User]> = try await request(
            environment: .production,
            path: "/v1/users"
        )
        guard let users = response.data else {
            throw NetworkError.noData
        }
        return users
    }
    
    func fetchUser(id: Int) async throws -> User {
        let response: APIResponse<User> = try await request(
            environment: .production,
            path: "/v1/users/\(id)"
        )
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
    
    func createUser(name: String, email: String) async throws -> User {
        let body = try JSONEncoder().encode(["name": name, "email": email])
        let response: APIResponse<User> = try await request(
            environment: .production,
            path: "/v1/users",
            method: "POST",
            body: body
        )
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
    
    // MARK: - Legacy System Methods
    
    func fetchLegacyRecords() async throws -> [LegacyRecord] {
        return try await request(
            environment: .legacy,
            path: "/api/records"
        )
    }
    
    func fetchLegacyRecord(id: String) async throws -> LegacyRecord {
        return try await request(
            environment: .legacy,
            path: "/api/records/\(id)"
        )
    }
    
    func updateLegacyRecord(id: String, value: String) async throws -> LegacyRecord {
        let body = try JSONEncoder().encode(["value": value])
        return try await request(
            environment: .legacy,
            path: "/api/records/\(id)",
            method: "PUT",
            body: body
        )
    }
}

// MARK: - View Model

@MainActor
class MainViewModel: ObservableObject {
    @Published var users: [User] = []
    @Published var legacyRecords: [LegacyRecord] = []
    @Published var isLoadingUsers = false
    @Published var isLoadingRecords = false
    @Published var errorMessage: String?
    @Published var connectionStatus: String = "Not connected"
    
    private let networkManager = NetworkManager.shared
    
    func authenticate(token: String) {
        networkManager.setAuthToken(token)
    }
    
    func fetchUsers() async {
        isLoadingUsers = true
        errorMessage = nil
        
        do {
            users = try await networkManager.fetchUsers()
            connectionStatus = "Connected to API (HTTPS)"
        } catch {
            errorMessage = error.localizedDescription
            connectionStatus = "API connection failed"
        }
        
        isLoadingUsers = false
    }
    
    func fetchLegacyRecords() async {
        isLoadingRecords = true
        errorMessage = nil
        
        do {
            legacyRecords = try await networkManager.fetchLegacyRecords()
            connectionStatus = "Connected to Legacy (HTTP)"
        } catch {
            errorMessage = error.localizedDescription
            connectionStatus = "Legacy connection failed"
        }
        
        isLoadingRecords = false
    }
    
    func createUser(name: String, email: String) async {
        errorMessage = nil
        
        do {
            let newUser = try await networkManager.createUser(name: name, email: email)
            users.append(newUser)
        } catch {
            errorMessage = error.localizedDescription
        }
    }
}

